import { useNavigate } from "react-router-dom";
import "./styles/Books.css";

const categories = [
  "Fantasy",
  "Literature",
  "Fiction",
  "Business",
  "SelfHelp",
  "Technology",
  "History",
  "Biography",
  "Philosophy",
  "Psychology",
  "Science",
  "Romance",
  "Mystery",
  "Horror",
  "Motivation",
  "Finance"
];

function Books() {
  const navigate = useNavigate();

  return (
    <div className="books-page">
      <h1 className="books-title">The Library</h1>

      <div className="books-grid">
        {categories.map((cat, i) => (
          <div
            key={i}
            className="book-card"
            onClick={() => navigate(`/category/${cat}`)}
          >
            <h3>{cat}</h3>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Books;
